var waPhone = function(phone) {
  if (!phone) return "";
  var p = phone.replace(/\s+/g, "").replace(/[^\d+]/g, "");
  if (p.startsWith("+")) return p.slice(1);
  if (p.startsWith("0")) return "20" + p.slice(1);
  return p;
};
var cleanPhone = function(phone) {
  if (!phone) return "";
  var p = phone.replace(/\s+/g, "").replace(/[^\d+]/g, "");
  if (!p) return "";
  if (p.startsWith("+")) return p;
  if (p.startsWith("20") && p.length > 10) return "+" + p;
  if (p.startsWith("0")) return p;
  if (p.length === 10) return "0" + p;
  return p;
};
var timeAgo = function(d, t) {
  if (!d) return "-";
  var diff = (Date.now() - new Date(d).getTime()) / 60000;
  // Defensive: future-dated values (data-entry bugs — e.g. a dealDate typed
  // as 2026-12-15 when meant 2026-02-15) make diff negative, which would
  // satisfy `diff < 1` below and render "Just now". Render the ISO date
  // instead so the bad date is visually obvious.
  if (diff < 0) return new Date(d).toISOString().slice(0,10);
  if (diff < 1) return t.just;
  if (diff < 60) return Math.floor(diff) + " " + t.minutes + " " + t.ago;
  if (diff < 1440) return Math.floor(diff / 60) + " " + t.hours + " " + t.ago;
  return Math.floor(diff / 1440) + " " + t.days + " " + t.ago;
};

// Forward-looking, compact time formatter for CallbackBell rows. The bell
// answers "when is the next call due?" — future rows read "in 2h" / "in 3d",
// overdue rows read "Overdue 2d". Compact units (m/h/d) with no space
// between qty and unit keep the row chip readable at 10px font.
var callbackTimeStr = function(d) {
  if (!d) return "-";
  var ts = new Date(d).getTime();
  if (isNaN(ts)) return "-";
  var diffMs = ts - Date.now();
  var absMin = Math.abs(diffMs) / 60000;
  var qty, unit;
  if (absMin < 60) { qty = Math.max(1, Math.round(absMin)); unit = "m"; }
  else if (absMin < 1440) { qty = Math.max(1, Math.round(absMin / 60)); unit = "h"; }
  else { qty = Math.max(1, Math.round(absMin / 1440)); unit = "d"; }
  return diffMs >= 0 ? ("in " + qty + unit) : ("Overdue " + qty + unit);
};

// 2026-05-18 — absolute date+time formatter for notification dropdowns.
// Used by the deal-bell and rotation-bell where every row should read as
// its own discrete event time. Relative "X days ago" hides per-row
// distinction when notifications cluster within the same window (the
// "1 days ago for every row" symptom we shipped to fix in 0e91a2c).
// Format: "15 May 2026 · 14:32" (locale-independent month abbrev).
var MONTHS_SHORT = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
var absoluteDateTime = function(d) {
  if (!d) return "-";
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return "-";
  var hh = String(dt.getHours()).padStart(2,"0");
  var mm = String(dt.getMinutes()).padStart(2,"0");
  return dt.getDate() + " " + MONTHS_SHORT[dt.getMonth()] + " " + dt.getFullYear() + " · " + hh + ":" + mm;
};

// Smart search: name, phone, last 4 digits
var matchSearch = function(lead, q) {
  if (!q) return true;
  q = q.toLowerCase().trim();
  if (lead.name.toLowerCase().includes(q)) return true;
  if (lead.phone.includes(q)) return true;
  if (lead.phone.slice(-4).includes(q)) return true;
  if (lead.phone2 && lead.phone2.includes(q)) return true;
  return false;
};

